import tensorflow as tfimport matplotlib.pyplot as plt# 定义初始值 权重和偏置TRUE_W = 3.0TRUE_B = 2.0# 获取训练数据，将训练数据与噪声进行综合NUM_EXAMPLES = 100inputs = tf.random.normal(shape=[NUM_EXAMPLES])noise = tf.random.normal(shape=[NUM_EXAMPLES])outputs = inputs * TRUE_W + TRUE_B + noise# 定义模型 w*x+bclass Model(object):    def __init__(self):        self.w = tf.Variable(1.2)        self.b = tf.Variable(0.5)    def __call__(self, inputs):        return self.w * inputs + self.b# 定义损失函数def compute_loss(y_true, y_pred):    return tf.reduce_mean(tf.square(y_true-y_pred))# 绘制数据 蓝色表示原始数据  红色表示预测数据plt.figure("一元线性回归")def plot(mod, epoch, loss):    plt.cla()    plt.scatter(inputs, outputs, c='b')    plt.plot(inputs, mod(inputs), c='r', linewidth=3)    plt.title("epoch %2d, loss = %s" % (epoch, str(loss)))    plt.ion()    plt.pause(0.08)    plt.ioff()def main():    model = Model()          # 创建模型    learning_rate = 0.05     # 学习率    loss_buf = []            # 存储每一个批次的损失值    for epoch in range(45):  # 轮数        with tf.GradientTape() as tape:  # 自动求梯度            loss = compute_loss(outputs, model(inputs))   # 计算损失值        dw, db = tape.gradient(loss, [model.w, model.b])  # 获取梯度值        # 衰减权重和偏置        model.w.assign_sub(learning_rate * dw)        model.b.assign_sub(learning_rate * db)        print("epoch %2d: w_true= %.2f, w_pred= %.2f; b_true= %.2f, b_pred= %.2f, loss= %.2f" %(              epoch+1, TRUE_W, model.w.numpy(), TRUE_B, model.b.numpy(), loss.numpy()))        loss_buf.append(loss.numpy())        plot(model, epoch, loss.numpy())    plt.figure("损失值")    plt.plot(loss_buf, c='g')    plt.xlim(0, 45)    plt.ylim(0, 8)    plt.xlabel('epoch', fontsize=10)    plt.ylabel('loss', fontsize=10)    plt.show()if __name__ == '__main__':    main()